#include <stdio.h>
#define MOD 1000000037
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int W, H, N;
        scanf("%d %d %d", &W, &H, &N);
        int xi[N], yi[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &xi[i], &yi[i]);
        }
        int dp[W+1][H+1] = {{0}};
        dp[0][0] = 1;
        for (int i = 0; i <= W; i++) {
            for (int j = 0; j <= H; j++) {
                if (i == 0 && j == 0) continue;
                int sum = 0;
                if (i > 0) sum += dp[i-1][j];
                if (j > 0) sum += dp[i][j-1];
                for (int k = 0; k < N; k++) {
                    if (i == xi[k] && j == yi[k]) {
                        sum = 0;
                        break;
                    }
                }
                dp[i][j] = sum % MOD;
            }
        }
        printf("%d\n", dp[W][H]);
    }
    return 0;
}

