const MOD = 1000000037;
const nextLine = () => lines[idx++];
const nextInt = () => parseInt(nextLine());
const nextInts = () => nextLine().split(' ').map(x => parseInt(x));
let T = nextInt();
while (T-- > 0) {
    let [W, H, N] = nextInts();
    let xi = [];
    let yi = [];
    for (let i = 0; i < N; i++) {
        let [x, y] = nextInts();
        xi.push(x);
        yi.push(y);
    }
    let dp = Array(W+1).fill(0).map(() => Array(H+1).fill(0));
    dp[0][0] = 1;
    for (let i = 0; i <= W; i++) {
        for (let j = 0; j <= H; j++) {
            if (i == 0 && j == 0) continue;
            let sum = 0;
            if (i > 0) sum += dp[i-1][j];
            if (j > 0) sum += dp[i][j-1];
            for (let k = 0; k < N; k++) {
                if (i == xi[k] && j == yi[k]) {
                    sum = 0;
                    break;
                }
            }
            dp[i][j] = sum % MOD;
        }
    }
    console.log(dp[W][H]);
